const cheerio = require('cheerio');

async function fetchURLMetadata(url) {
  if (!url || typeof url !== 'string' || (!url.startsWith('http://') && !url.startsWith('https://'))) {
    throw new Error('Invalid URL provided. URL must be a string starting with http(s).');
  }

  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 10000); // 10 seconds timeout

    const response = await fetch(url, {
      redirect: 'follow', // Follow redirects by default
      signal: controller.signal
    });

    clearTimeout(timeoutId);

    if (!response.ok) {
      throw new Error(`HTTP error! Status: ${response.status} for URL: ${url}`);
    }

    const contentType = response.headers.get('content-type');
    // Only process HTML content, ignoring charset for simplicity
    if (!contentType || !contentType.includes('text/html')) {
      throw new Error(`URL content type is not HTML: ${contentType} for URL: ${url}`);
    }

    const html = await response.text();
    const $ = cheerio.load(html);

    const metadata = {
      title: null,
      description: null,
      og: {},
    };

    // Extract title
    const pageTitle = $('title').text();
    if (pageTitle) {
      metadata.title = pageTitle.trim();
    }

    // Extract meta description
    const metaDescription = $('meta[name="description"]').attr('content');
    if (metaDescription) {
      metadata.description = metaDescription.trim();
    }

    // Extract Open Graph tags
    $('meta[property^="og:"]').each((index, element) => {
      const property = $(element).attr('property');
      const content = $(element).attr('content');
      if (property && content) {
        // Remove 'og:' prefix and store
        const key = property.substring(3);
        metadata.og[key] = content.trim();
      }
    });

    // Fallback for top-level title and description using Open Graph if not found directly
    metadata.title = metadata.title || metadata.og.title || null;
    metadata.description = metadata.description || metadata.og.description || null;

    return metadata;

  } catch (error) {
    if (error.name === 'AbortError') {
      console.error(`Request to ${url} timed out.`);
      throw new Error(`Timeout fetching metadata for ${url}`);
    }
    console.error(`Error fetching metadata for ${url}: ${error.message}`);
    throw error;
  }
}

